import {
  HoverCard as HoverCardPrimitive,
  useHoverCard,
  useHoverCardContext,
} from '@ark-ui/react/hover-card';
import { clsx } from 'clsx';
import type { ComponentProps, ComponentRef } from 'react';
import { forwardRef } from 'react';
import { normalizeClassName } from '@/lib/moduix/normalizeClassName';
import {
  OverlayPortal,
  OverlayPortalProvider,
  type OverlayPortalProps,
} from '@/lib/moduix/overlayPortal';
import styles from './HoverCard.module.css';

type HoverCardRootProps = ComponentProps<typeof HoverCardPrimitive.Root> & OverlayPortalProps;
type HoverCardRootProviderProps = ComponentProps<typeof HoverCardPrimitive.RootProvider> &
  OverlayPortalProps;

function HoverCardRoot({ portalled, portalRef, ...props }: HoverCardRootProps) {
  return (
    <OverlayPortalProvider portalled={portalled} portalRef={portalRef}>
      <HoverCardPrimitive.Root data-slot="hover-card-root" {...props} />
    </OverlayPortalProvider>
  );
}

function HoverCardRootProvider({ portalled, portalRef, ...props }: HoverCardRootProviderProps) {
  return (
    <OverlayPortalProvider portalled={portalled} portalRef={portalRef}>
      <HoverCardPrimitive.RootProvider data-slot="hover-card-root-provider" {...props} />
    </OverlayPortalProvider>
  );
}

const HoverCardTrigger = forwardRef<
  ComponentRef<typeof HoverCardPrimitive.Trigger>,
  ComponentProps<typeof HoverCardPrimitive.Trigger>
>(function HoverCardTrigger({ asChild, className, ...props }, ref) {
  return (
    <HoverCardPrimitive.Trigger
      ref={ref}
      data-slot="hover-card-trigger"
      asChild={asChild}
      className={clsx(!asChild && styles.trigger, normalizeClassName(className))}
      {...props}
    />
  );
});

const HoverCardPositioner = forwardRef<
  ComponentRef<typeof HoverCardPrimitive.Positioner>,
  ComponentProps<typeof HoverCardPrimitive.Positioner>
>(function HoverCardPositioner({ className, ...props }, ref) {
  return (
    <OverlayPortal>
      <HoverCardPrimitive.Positioner
        ref={ref}
        data-slot="hover-card-positioner"
        className={clsx(styles.positioner, normalizeClassName(className))}
        {...props}
      />
    </OverlayPortal>
  );
});

const HoverCardContent = forwardRef<
  ComponentRef<typeof HoverCardPrimitive.Content>,
  ComponentProps<typeof HoverCardPrimitive.Content>
>(function HoverCardContent({ className, ...props }, ref) {
  return (
    <HoverCardPrimitive.Content
      ref={ref}
      data-slot="hover-card-content"
      className={clsx(styles.content, normalizeClassName(className))}
      {...props}
    />
  );
});

const HoverCardArrow = forwardRef<
  ComponentRef<typeof HoverCardPrimitive.Arrow>,
  ComponentProps<typeof HoverCardPrimitive.Arrow>
>(function HoverCardArrow({ className, children, ...props }, ref) {
  return (
    <HoverCardPrimitive.Arrow
      ref={ref}
      data-slot="hover-card-arrow"
      className={clsx(styles.arrow, normalizeClassName(className))}
      {...props}
    >
      {children ?? <HoverCardArrowTip />}
    </HoverCardPrimitive.Arrow>
  );
});

const HoverCardArrowTip = forwardRef<
  ComponentRef<typeof HoverCardPrimitive.ArrowTip>,
  ComponentProps<typeof HoverCardPrimitive.ArrowTip>
>(function HoverCardArrowTip({ className, ...props }, ref) {
  return (
    <HoverCardPrimitive.ArrowTip
      ref={ref}
      data-slot="hover-card-arrow-tip"
      className={clsx(styles.arrowTip, normalizeClassName(className))}
      {...props}
    />
  );
});

const HoverCard = Object.assign(HoverCardRoot, {
  Root: HoverCardRoot,
  RootProvider: HoverCardRootProvider,
  Trigger: HoverCardTrigger,
  Positioner: HoverCardPositioner,
  Content: HoverCardContent,
  Arrow: HoverCardArrow,
  ArrowTip: HoverCardArrowTip,
  Context: HoverCardPrimitive.Context,
});

export { HoverCard, useHoverCard, useHoverCardContext };

@layer ui.components {
  .trigger {
    --hover-card-trigger-current-color: var(--hover-card-trigger-color, var(--color-primary));

    display: inline-flex;
    align-items: center;
    gap: var(--hover-card-trigger-gap, 0.25rem);
    outline: 0;
    color: var(--hover-card-trigger-current-color);
    font: inherit;
    text-decoration-line: underline;
    text-decoration-thickness: var(--hover-card-trigger-decoration-thickness, 1px);
    text-decoration-color: var(
      --hover-card-trigger-decoration-color,
      color-mix(in oklab, var(--hover-card-trigger-current-color), transparent 40%)
    );
    text-underline-offset: var(--hover-card-trigger-underline-offset, 2px);
    cursor: pointer;
    transition:
      color var(--hover-card-transition, var(--duration-fast)),
      text-decoration-color var(--hover-card-transition, var(--duration-fast));

    @media (hover: hover) {
      &:hover {
        text-decoration-color: var(
          --hover-card-trigger-decoration-color-hover,
          var(--hover-card-trigger-current-color)
        );
      }
    }

    &[data-state='open'] {
      text-decoration-color: var(
        --hover-card-trigger-decoration-color-open,
        var(--hover-card-trigger-current-color)
      );
    }

    &:focus-visible {
      border-radius: var(--hover-card-trigger-focus-radius, var(--radius-xs));
      outline: var(--hover-card-focus-ring-width, var(--border-width-sm)) solid
        var(--hover-card-focus-ring-color, var(--color-ring));
      outline-offset: var(--hover-card-trigger-focus-offset, 1px);
      text-decoration-line: none;
    }

    &:is([data-disabled], [disabled]) {
      pointer-events: none;
      opacity: var(--hover-card-disabled-opacity, var(--opacity-disabled));
    }
  }

  .positioner {
    z-index: var(--z-index, var(--z-popup));
    max-width: var(--available-width);
    outline: 0;
  }

  .content {
    position: relative;
    z-index: calc(var(--z-popup) + var(--layer-index, 0));
    box-sizing: border-box;
    width: var(--hover-card-width, auto);
    height: var(--hover-card-height, auto);
    min-width: min(var(--hover-card-min-width, 14rem), var(--available-width));
    max-width: min(var(--hover-card-max-width, 24rem), var(--available-width));
    max-height: min(var(--hover-card-max-height, 24rem), var(--available-height, 100dvh));
    overflow: visible;
    padding: var(--hover-card-padding-y, var(--spacing-2))
      var(--hover-card-padding-x, var(--spacing-2));
    border: 0;
    border-radius: var(--hover-card-radius, var(--radius-lg));
    background-color: var(--hover-card-bg, var(--color-popover));
    color: var(--hover-card-color, var(--color-popover-foreground));
    outline: var(--hover-card-border-width, var(--border-width-sm)) solid
      var(--hover-card-border-color, var(--color-border));
    box-shadow: var(--hover-card-shadow, var(--shadow-lg));
    transform-origin: var(--transform-origin);

    &[data-state='open'] {
      animation: hover-card-enter
        var(
          --hover-card-transition,
          var(--popup-motion-duration, var(--duration-fast)) var(--popup-motion-easing, ease)
        )
        both;
    }

    &[data-state='closed'] {
      animation: hover-card-exit
        var(
          --hover-card-transition,
          var(--popup-motion-duration, var(--duration-fast)) var(--popup-motion-easing, ease)
        )
        both;
    }
  }

  .arrow {
    --arrow-size: var(--hover-card-arrow-size, 0.625rem);
    --arrow-background: var(--hover-card-bg, var(--color-popover));
  }

  .arrowTip {
    border-top: var(--hover-card-border-width, var(--border-width-sm)) solid
      var(--hover-card-arrow-stroke-color, var(--hover-card-border-color, var(--color-border)));
    border-left: var(--hover-card-border-width, var(--border-width-sm)) solid
      var(--hover-card-arrow-stroke-color, var(--hover-card-border-color, var(--color-border)));
  }

  @keyframes hover-card-enter {
    from {
      opacity: var(--hover-card-content-starting-opacity, var(--popup-motion-starting-opacity, 0));
      translate: var(
          --hover-card-content-starting-translate-x,
          var(--popup-motion-starting-translate-x, 0)
        )
        var(--hover-card-content-starting-translate-y, var(--popup-motion-starting-translate-y, 0));
      scale: var(
        --hover-card-content-starting-scale,
        var(--popup-motion-starting-scale, var(--scale-popup))
      );
    }
  }

  @keyframes hover-card-exit {
    to {
      opacity: var(--hover-card-content-ending-opacity, var(--popup-motion-ending-opacity, 0));
      translate: var(
          --hover-card-content-ending-translate-x,
          var(--popup-motion-ending-translate-x, 0)
        )
        var(--hover-card-content-ending-translate-y, var(--popup-motion-ending-translate-y, 0));
      scale: var(
        --hover-card-content-ending-scale,
        var(--popup-motion-ending-scale, var(--scale-popup))
      );
    }
  }
}
